type State = { fields: Record<string, string>; errors: Record<string, string>; isSubmitting: boolean };
type Action = { type: 'SET_FIELD'; field: string; value: string } | { type: 'VALIDATE' } | { type: 'SUBMIT_START' };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'SET_FIELD': return { ...state, fields: { ...state.fields, [action.field]: action.value } };
    case 'VALIDATE': return { ...state, errors: validate(state.fields) };
    case 'SUBMIT_START': return { ...state, isSubmitting: true };
  }
}

