function classifyError(error: Error): 'recoverable' | 'escalate' {
  if (error.name === 'NetworkError' || error.message.includes('fetch failed')) return 'recoverable';
  if (error.message.includes('AbortError')) return 'recoverable';
  return 'escalate';
}

function GlobalErrorHandler({ children }: { children: React.ReactNode }) {
  return (
    <ErrorBoundary
      onError={(error, info) => {
        telemetry.error('render_error', { error: error.message, stack: info.componentStack });
      }}
      fallback={({ error, resetErrorBoundary }) => {
        const classification = classifyError(error);
        if (classification === 'recoverable') {
          setTimeout(resetErrorBoundary, 1000);  // auto-retry
          return <SubtleSpinner />;
        }
        return <FullErrorScreen error={error} onRetry={resetErrorBoundary} />;
      }}
    >
      {children}
    </ErrorBoundary>
  );
}

