type Events = {
  'user.signedIn': { userId: string };
  'cart.added': { productId: string; quantity: number };
};

class EventBus<T extends Record<string, unknown>> {
  private listeners = new Map<keyof T, Set<(payload: any) => void>>();
  on<K extends keyof T>(event: K, handler: (payload: T[K]) => void) {
    let set = this.listeners.get(event);
    if (!set) { set = new Set(); this.listeners.set(event, set); }
    set.add(handler);
    return () => { set!.delete(handler); };
  }
  emit<K extends keyof T>(event: K, payload: T[K]) {
    this.listeners.get(event)?.forEach(h => h(payload));
  }
}

export const bus = new EventBus<Events>();

