import { useState, useRef, useEffect } from 'react';

function useHover() {
  const [hovered, setHovered] = useState(false);
  const ref = useRef<HTMLElement>(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const enter = () => setHovered(true);
    const leave = () => setHovered(false);
    el.addEventListener('mouseenter', enter);
    el.addEventListener('mouseleave', leave);
    return () => {
      el.removeEventListener('mouseenter', enter);
      el.removeEventListener('mouseleave', leave);
    };
  }, []);
  return [ref, hovered] as const;
}

function useWizardStack(steps: string[]) {
  const [stack, setStack] = useState<string[]>([steps[0]]);
  const current = stack[stack.length - 1];
  const goTo = (step: string) => setStack(s => [...s, step]);
  const back = () => setStack(s => s.length > 1 ? s.slice(0, -1) : s);
  return { current, goTo, back, canBack: stack.length > 1 };
}

import { useEffect, useState } from 'react';

export function useLiveMetrics() {
  const [metrics, setMetrics] = useState<Metric[]>([]);
  useEffect(() => {
    const es = new EventSource('/api/metrics/stream');
    es.onmessage = (e) => {
      const data = JSON.parse(e.data);
      setMetrics(prev => [...prev, data].slice(-100));
    };
    es.onerror = () => es.close();
    return () => es.close();
  }, []);
  return metrics;
}

