function trackEvent(name: string, data: object) {
  const send = () => {
    navigator.sendBeacon('/api/analytics', JSON.stringify({ name, data }));
  };
  if ('requestIdleCallback' in window) {
    (window as any).requestIdleCallback(send, { timeout: 2000 });
  } else {
    setTimeout(send, 0);
  }
}

